from http.server import BaseHTTPRequestHandler
import json, io, base64, os
from datetime import date, datetime

VOUCHER_BG_B64 = ""
LOGO_B64       = ""


def _fmtd(d):
    if not d: return ""
    s = str(d)[:10]
    if "-" in s:
        p = s.split("-")
        return f"{p[2]}/{p[1]}/{p[0][-2:]}"
    return s

def _fmtd_full(d):
    if not d: return ""
    s = str(d)[:10]
    if "-" in s:
        p = s.split("-")
        return f"{p[2]}/{p[1]}/{p[0]}"
    return s

def _noches(a, b):
    try:
        return (datetime.fromisoformat(str(b)[:10]) - datetime.fromisoformat(str(a)[:10])).days
    except: return 0

def _pax_v(r):
    p = []
    if r.get("adultos"): p.append(f"Adl: {r['adultos']}")
    if r.get("chd"):     p.append(f"Chd: {r['chd']}")
    if r.get("inf"):     p.append(f"Inf: {r['inf']}")
    return " / ".join(p)

def _pax_c(r):
    p = []
    if r.get("adultos"): p.append(f"Adultos: {r['adultos']}")
    if r.get("chd"):     p.append(f"Menores: {r['chd']}")
    if r.get("inf"):     p.append(f"Infantes: {r['inf']}")
    return "  /  ".join(p)


def gen_voucher_pdf(r):
    from PIL import Image, ImageDraw, ImageFont
    from reportlab.pdfgen import canvas as rl_canvas
    from reportlab.lib.utils import ImageReader

    bg = Image.open(io.BytesIO(base64.b64decode(VOUCHER_BG_B64))).copy()
    draw = ImageDraw.Draw(bg)
    NAVY = (26, 39, 68)

    try:
        font_md = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 30)
        font_sm = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf", 26)
        font_lg = ImageFont.truetype("/usr/share/fonts/truetype/dejavu/DejaVuSans-Bold.ttf", 30)
    except Exception:
        font_md = font_sm = font_lg = ImageFont.load_default()

    hotel   = (r.get("proveedor_nombre") or r.get("destino","")).upper()
    codigo  = r.get("cod_proveedor","") or ""
    servicio = ", ".join(filter(None,[r.get("habitacion",""), r.get("regimen","")]))
    benef   = f"{r.get('pasajero_nombre','')} ({_pax_v(r)})"
    hoy     = date.today().strftime("%d/%m/%y")
    nn      = _noches(r.get("fecha_in"), r.get("fecha_out"))

    # posiciones calibradas sobre imagen 1772x1766
    draw.text((1232,  84), hoy,                      font=font_sm, fill=NAVY)
    draw.text((87,   575), hotel,                    font=font_lg, fill=NAVY)
    draw.text((673,  580), codigo,                   font=font_md, fill=NAVY)
    draw.text((87,   943), servicio,                 font=font_md, fill=NAVY)
    draw.text((87,  1075), benef,                    font=font_md, fill=NAVY)
    draw.text((1309, 884), _fmtd(r.get("fecha_in")), font=font_md, fill=NAVY)
    draw.text((1344, 943), _fmtd(r.get("fecha_out")),font=font_md, fill=NAVY)
    draw.text((1215,1020), f"({nn} noches)",          font=font_md, fill=NAVY)

    img_buf = io.BytesIO()
    bg.save(img_buf, format="PNG")
    img_buf.seek(0)

    pdf_buf = io.BytesIO()
    c = rl_canvas.Canvas(pdf_buf, pagesize=(595, 595))
    c.drawImage(ImageReader(img_buf), 0, 0, 595, 595)
    c.save()
    pdf_buf.seek(0)
    return pdf_buf.read()


def gen_confirmacion_pdf(r):
    from reportlab.platypus import SimpleDocTemplate, Table, TableStyle, Paragraph, Spacer
    from reportlab.platypus import Image as RLImage
    from reportlab.lib.styles import ParagraphStyle
    from reportlab.lib import colors
    from reportlab.lib.pagesizes import A4
    from reportlab.lib.units import cm
    from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
    from reportlab.lib.utils import ImageReader
    from PIL import Image

    navy = colors.HexColor("#1a2744")
    buf  = io.BytesIO()

    logo_img = Image.open(io.BytesIO(base64.b64decode(LOGO_B64)))
    lw, lh   = logo_img.size
    logo_pt_w = 120
    logo_pt_h = logo_pt_w * (lh / lw)
    logo_buf  = io.BytesIO()
    logo_img.save(logo_buf, format="PNG")
    logo_buf.seek(0)

    doc = SimpleDocTemplate(buf, pagesize=A4,
        topMargin=1.5*cm, bottomMargin=1.5*cm,
        leftMargin=2*cm, rightMargin=2*cm)

    S = lambda name, **kw: ParagraphStyle(name, fontName="Helvetica", fontSize=11, textColor=navy, **kw)
    s_fecha = S("sf", fontSize=10, alignment=TA_RIGHT)
    s_hotel = S("sh", fontSize=13, fontName="Helvetica-Bold", alignment=TA_CENTER)
    s_cell  = S("sc", alignment=TA_CENTER)
    s_lbl   = S("sl", alignment=TA_LEFT)

    hotel   = r.get("proveedor_nombre") or r.get("destino","")
    titular = r.get("pasajero_nombre","")
    hab     = r.get("habitacion","-") or "-"
    obs     = r.get("regimen","N/A") or "N/A"
    moneda  = r.get("moneda","USD")
    total   = f"{moneda} {int(r['venta'])}.-" if r.get("venta") else "-"
    nn      = _noches(r.get("fecha_in"), r.get("fecha_out"))
    hoy     = date.today().strftime("%d/%m/%Y")

    P = lambda txt, sty: Paragraph(txt, sty)
    td = [
        [P("Titular:",       s_lbl), P(titular,                       s_cell), ""],
        [P("Pasajeros:",     s_lbl), P(_pax_c(r),                     s_cell), ""],
        [P("Fecha In:",      s_lbl), P(_fmtd_full(r.get("fecha_in")), s_cell), P(f"Noches: {nn}", s_cell)],
        [P("Check Out:",     s_lbl), P(_fmtd_full(r.get("fecha_out")),s_cell), ""],
        [P("Habitaciones:",  s_lbl), P(hab,                           s_cell), ""],
        [P("Observaciones:", s_lbl), P(obs,                           s_cell), ""],
        [P("Total:",         s_lbl), P(total,                         s_cell), ""],
    ]
    COL1=4.5*cm; COL2=7*cm; COL3=3*cm
    tbl = Table(td, colWidths=[COL1, COL2, COL3])
    tbl.setStyle(TableStyle([
        ("GRID",          (0,0),(-1,-1), 0.5, colors.HexColor("#aaaaaa")),
        ("VALIGN",        (0,0),(-1,-1), "MIDDLE"),
        ("TOPPADDING",    (0,0),(-1,-1), 8),
        ("BOTTOMPADDING", (0,0),(-1,-1), 8),
        ("SPAN",          (1,0),(2,0)),
        ("SPAN",          (1,1),(2,1)),
        ("SPAN",          (2,2),(2,3)),
        ("SPAN",          (1,4),(2,4)),
        ("SPAN",          (1,5),(2,5)),
        ("SPAN",          (1,6),(2,6)),
    ]))

    logo_rl = RLImage(logo_buf, width=logo_pt_w, height=logo_pt_h)
    logo_rl.hAlign = "CENTER"

    story = [
        P(f"<b>Fecha de reserva:</b>  {hoy}", s_fecha),
        Spacer(1, 0.3*cm),
        logo_rl,
        Spacer(1, 0.4*cm),
        P(hotel, s_hotel),
        Spacer(1, 0.5*cm),
        tbl,
    ]
    doc.build(story)
    buf.seek(0)
    return buf.read()


class handler(BaseHTTPRequestHandler):
    def do_POST(self):
        try:
            length = int(self.headers.get("Content-Length", 0))
            body   = json.loads(self.rfile.read(length))
            tipo   = body.get("tipo")
            r      = body.get("reserva", {})

            if not tipo or not r:
                self._respond(400, {"error": "Faltan campos"})
                return

            nombre = r.get("pasajero_nombre","")
            hotel  = r.get("proveedor_nombre") or r.get("destino","")

            if tipo == "voucher":
                pdf   = gen_voucher_pdf(r)
                fname = f"Voucher_{nombre.replace(' ','_')}.pdf"
                subj  = f"Voucher de viaje — {hotel}"
            else:
                pdf   = gen_confirmacion_pdf(r)
                fname = f"Confirmacion_{nombre.replace(' ','_')}.pdf"
                subj  = f"Confirmacion de reserva — {hotel}"

            self._respond(200, {
                "ok":       True,
                "pdf":      base64.b64encode(pdf).decode(),
                "filename": fname,
                "subject":  subj,
                "nombre":   nombre,
            })

        except Exception as e:
            import traceback
            self._respond(500, {"error": str(e), "trace": traceback.format_exc()})

    def _respond(self, code, data):
        body = json.dumps(data).encode()
        self.send_response(code)
        self.send_header("Content-Type", "application/json")
        self.send_header("Content-Length", len(body))
        self.end_headers()
        self.wfile.write(body)

    def log_message(self, *args):
        pass
